refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_fruits.jpg"));
image = imresize(image, [120 160]);
gray = rgb2gray(image);
volume = cat(3, gray, imtranslate(gray, [2 0]), imtranslate(gray, [4 0]));
[magnitude, gx, gy, gz] = imgradient3(volume);
imshow3d(magnitude, 2);
